/**
 * Structured representation of the parsed time.
 * @deprecated The `TimeDetails` interface will be removed, please use `TimeValue` instead.
 * @public
 */
export interface TimeDetails {
    /** Input candidate trimmed of whitespaces. */
    normalized: string;
    /** Date representation of the converted input candidate. */
    date: Date;
    /**
     * Type of the given time, which can either be an ISO string
     * or a relative time expression (e.g. Last 30 minutes).
     */
    type: 'expression' | 'iso8601';
}
/** @internal */
export type _TimeOffsetValue = number | 'endOfDay' | 'startOfDay' | (string & {});
/**
 * Offset applied to a time in milliseconds or literals for end or start of the day.
 * @internal
 */
export type _TimeOffset = _TimeOffsetValue | {
    from: _TimeOffsetValue;
    to: _TimeOffsetValue;
};
/**
 * The value of a part of a time frame.
 * @public
 */
export interface TimeValue {
    /** The actual selected date as ISOString, equals the value in case of an 'iso8601'-type. */
    absoluteDate: string;
    /** The sanitized value. */
    value: string;
    /** Defines the type of the value. */
    type: 'expression' | 'iso8601';
}
/**
 * Defines a timeframe with a `from` and `to` property.
 * @public
 */
export interface Timeframe {
    /** Start of the time frame. */
    from: TimeValue;
    /** End of the time frame. */
    to: TimeValue;
}
